import{_ as a,o as e,c as d,ag as l}from"./chunks/framework.CAXxHpAX.js";const c=JSON.parse('{"title":"第 11 章 决策树","description":"","frontmatter":{},"headers":[],"relativePath":"ml/random-forest.md","filePath":"ml/random-forest.md","lastUpdated":1777728844000}'),i={name:"ml/random-forest.md"};function r(p,t,s,n,o,h){return e(),d("div",null,[...t[0]||(t[0]=[l(`<h1 id="第-11-章-决策树" tabindex="-1">第 11 章 决策树 <a class="header-anchor" href="#第-11-章-决策树" aria-label="Permalink to &quot;第 11 章 决策树&quot;">​</a></h1><p>随机森林是一种集成学习方法。它不是训练一棵决策树，而是训练多棵决策树，再把这些树的结果综合起来。</p><p>随机森林常用于表格数据，优点是效果稳定、对特征缩放不敏感、能处理非线性关系，也不容易像单棵决策树那样过拟合。</p><h2 id="_11-1-决策树" tabindex="-1">11.1 决策树 <a class="header-anchor" href="#_11-1-决策树" aria-label="Permalink to &quot;11.1 决策树&quot;">​</a></h2><p>决策树通过一系列判断条件把样本划分到不同叶子节点。</p><p>例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>年龄 &lt; 30 ?</span></span>
<span class="line"><span>  是 -&gt; 收入 &lt; 8000 ?</span></span>
<span class="line"><span>  否 -&gt; 工作年限 &lt; 5 ?</span></span></code></pre></div><p>每个内部节点是一个划分规则，每个叶子节点给出预测结果。</p><p>决策树可以用于分类，也可以用于回归。</p><table tabindex="0"><thead><tr><th>任务</th><th>叶子节点输出</th></tr></thead><tbody><tr><td>分类</td><td>类别或类别概率</td></tr><tr><td>回归</td><td>数值预测</td></tr></tbody></table><h2 id="_11-2-划分标准" tabindex="-1">11.2 划分标准 <a class="header-anchor" href="#_11-2-划分标准" aria-label="Permalink to &quot;11.2 划分标准&quot;">​</a></h2><p>决策树训练时要选择特征和阈值，让划分后的数据更“纯”。</p><p>分类树常用指标：</p><table tabindex="0"><thead><tr><th>指标</th><th>含义</th></tr></thead><tbody><tr><td>信息增益</td><td>划分后熵减少多少</td></tr><tr><td>增益率</td><td>对信息增益做修正</td></tr><tr><td>基尼指数</td><td>衡量类别混杂程度</td></tr></tbody></table><p>回归树常用平方误差来选择划分，使划分后每个区域内的目标值更接近。</p><h2 id="_11-3-单棵决策树的问题" tabindex="-1">11.3 单棵决策树的问题 <a class="header-anchor" href="#_11-3-单棵决策树的问题" aria-label="Permalink to &quot;11.3 单棵决策树的问题&quot;">​</a></h2><p>决策树的优点是直观、可解释、不需要特征缩放。</p><p>但单棵决策树容易过拟合。树越深，就越可能把训练集中的噪声也记住。</p><p>常见控制方法：</p><ul><li>限制最大深度。</li><li>限制叶子节点最小样本数。</li><li>剪枝。</li><li>限制每次划分可用特征。</li></ul><p>随机森林就是在“多棵不完全相同的树”基础上缓解过拟合。</p><h2 id="_11-4-bagging" tabindex="-1">11.4 Bagging <a class="header-anchor" href="#_11-4-bagging" aria-label="Permalink to &quot;11.4 Bagging&quot;">​</a></h2><p>Bagging 是 Bootstrap Aggregating 的缩写。</p><p>它的基本思想：</p><ol><li>从训练集中有放回地抽样，得到多个不同子数据集。</li><li>在每个子数据集上训练一个模型。</li><li>把多个模型的预测结果综合起来。</li></ol><p>分类任务通常投票：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>多数树预测为哪一类，最终就预测哪一类</span></span></code></pre></div><p>回归任务通常取平均：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>多棵树预测值的平均值作为最终输出</span></span></code></pre></div><p>Bagging 可以降低方差，让模型结果更稳定。</p><h2 id="_11-5-随机森林" tabindex="-1">11.5 随机森林 <a class="header-anchor" href="#_11-5-随机森林" aria-label="Permalink to &quot;11.5 随机森林&quot;">​</a></h2><p>随机森林可以看作 Bagging + 决策树 + 特征随机选择。</p><p>它的随机性主要来自两处：</p><table tabindex="0"><thead><tr><th>随机性</th><th>作用</th></tr></thead><tbody><tr><td>样本随机</td><td>每棵树使用 bootstrap 抽样得到的数据</td></tr><tr><td>特征随机</td><td>每个节点划分时只从部分特征中选择</td></tr></tbody></table><p>如果每棵树都很相似，集成效果有限。样本随机和特征随机会让树之间产生差异，从而降低整体方差。</p><h2 id="_11-6-训练和预测" tabindex="-1">11.6 训练和预测 <a class="header-anchor" href="#_11-6-训练和预测" aria-label="Permalink to &quot;11.6 训练和预测&quot;">​</a></h2><p>训练过程：</p><ol><li>生成多个 bootstrap 数据集。</li><li>在每个数据集上训练一棵决策树。</li><li>每个节点划分时，只随机选择一部分特征参与比较。</li><li>得到多棵树组成的森林。</li></ol><p>预测过程：</p><table tabindex="0"><thead><tr><th>任务</th><th>随机森林输出</th></tr></thead><tbody><tr><td>分类</td><td>多数投票</td></tr><tr><td>回归</td><td>平均预测值</td></tr></tbody></table><h2 id="_11-7-随机森林的优缺点" tabindex="-1">11.7 随机森林的优缺点 <a class="header-anchor" href="#_11-7-随机森林的优缺点" aria-label="Permalink to &quot;11.7 随机森林的优缺点&quot;">​</a></h2><p>优点：</p><ul><li>能处理非线性关系。</li><li>不需要特征缩放。</li><li>对异常值相对鲁棒。</li><li>比单棵决策树更不容易过拟合。</li><li>可以估计特征重要性。</li></ul><p>缺点：</p><ul><li>可解释性不如单棵决策树。</li><li>模型体积更大。</li><li>预测速度比单棵树慢。</li><li>对高维稀疏文本特征不一定是最佳选择。</li></ul><h2 id="_11-8-和其他模型的区别" tabindex="-1">11.8 和其他模型的区别 <a class="header-anchor" href="#_11-8-和其他模型的区别" aria-label="Permalink to &quot;11.8 和其他模型的区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模型</th><th>特点</th></tr></thead><tbody><tr><td>逻辑回归</td><td>线性分类模型，简单可解释</td></tr><tr><td>SVM</td><td>关注间隔，可配合核函数处理非线性</td></tr><tr><td>决策树</td><td>规则划分，可解释但容易过拟合</td></tr><tr><td>随机森林</td><td>多棵树集成，稳定性更好</td></tr></tbody></table><p>随机森林属于 Bagging 思想，重点是降低方差。后续如果学习 GBDT、XGBoost、LightGBM，它们属于 Boosting 思想，重点是逐步修正前面模型的错误。</p>`,48)])])}const g=a(i,[["render",r]]);export{c as __pageData,g as default};
